#!/usr/bin/env python3
"""
gate_checker.py — reads a design document and evaluates gate criteria.

Usage:
  python gate_checker.py --gate architecture_review \
                         --design design/architecture_design_document.md \
                         --config gates/architecture_review.yaml

Exit codes:
  0 — all auto criteria passed
  1 — one or more auto criteria failed
  2 — configuration or input error
"""

from __future__ import annotations
import argparse
import json
import re
import sys
from dataclasses import dataclass, field
from pathlib import Path
from typing import Any

import yaml  # pip install pyyaml


# ---------------------------------------------------------------------------
# Data structures
# ---------------------------------------------------------------------------

@dataclass
class CriterionResult:
    criterion_id: str
    description: str
    passed: bool
    evidence: str = ""
    mode: str = "auto"   # "auto" | "manual"


@dataclass
class GateReport:
    gate_id: str
    design_path: str
    auto_results: list[CriterionResult] = field(default_factory=list)
    manual_checklist: list[CriterionResult] = field(default_factory=list)

    @property
    def auto_passed(self) -> bool:
        return all(r.passed for r in self.auto_results)

    @property
    def summary(self) -> dict[str, Any]:
        return {
            "gate_id": self.gate_id,
            "auto_passed": self.auto_passed,
            "auto_failures": [r.criterion_id for r in self.auto_results if not r.passed],
            "manual_items": [r.criterion_id for r in self.manual_checklist],
        }


# ---------------------------------------------------------------------------
# Design document parser (Markdown-based)
# ---------------------------------------------------------------------------

class DesignDocParser:
    """Extract structured signals from a Markdown design document."""

    def __init__(self, path: Path) -> None:
        self.text = path.read_text(encoding="utf-8")
        self._sections: dict[str, str] = self._split_sections()

    def _split_sections(self) -> dict[str, str]:
        sections: dict[str, str] = {}
        current = "__preamble__"
        buf: list[str] = []
        for line in self.text.splitlines():
            if line.startswith("#"):
                sections[current] = "\n".join(buf)
                current = line.lstrip("#").strip().lower()
                buf = []
            else:
                buf.append(line)
        sections[current] = "\n".join(buf)
        return sections

    def has_section(self, keyword: str) -> bool:
        return any(keyword in k for k in self._sections)

    def section_text(self, keyword: str) -> str:
        for k, v in self._sections.items():
            if keyword in k:
                return v
        return ""

    def count_tool_scopes(self) -> int:
        """Rough heuristic: count 'scope:' lines in the tools section."""
        tools_text = self.section_text("tool")
        return len(re.findall(r"scope:", tools_text, re.IGNORECASE))

    def max_loop_depth_declared(self) -> int:
        """Look for explicit max_loop_depth declaration."""
        match = re.search(r"max_loop_depth[:\s]+([0-9]+)", self.text)
        return int(match.group(1)) if match else 0

    def has_eval_baseline(self) -> bool:
        return bool(re.search(r"baseline|eval suite|evaluation harness", self.text, re.IGNORECASE))

    def pii_documented(self) -> bool:
        return bool(re.search(r"PII|personally identifiable|data flow diagram", self.text, re.IGNORECASE))


# ---------------------------------------------------------------------------
# Gate evaluator
# ---------------------------------------------------------------------------

class GateEvaluator:
    """Evaluate auto criteria from a gate config against a design document."""

    def __init__(self, config_path: Path) -> None:
        with config_path.open() as fh:
            self.config: dict[str, Any] = yaml.safe_load(fh)

    def evaluate(self, doc: DesignDocParser) -> GateReport:
        report = GateReport(
            gate_id=self.config["gate_id"],
            design_path=str(doc),
        )

        for crit in self.config.get("exit_criteria", {}).get("auto", []):
            result = self._check_auto(crit, doc)
            report.auto_results.append(result)

        for crit in self.config.get("exit_criteria", {}).get("manual", []):
            report.manual_checklist.append(
                CriterionResult(
                    criterion_id=crit["id"],
                    description=crit["description"],
                    passed=False,   # manual — needs human sign-off
                    mode="manual",
                )
            )

        return report

    def _check_auto(self, crit: dict, doc: DesignDocParser) -> CriterionResult:
        cid = crit["id"]
        desc = crit.get("description", cid)

        # Dispatch on known criterion IDs
        if cid == "no_unbounded_loops":
            depth = doc.max_loop_depth_declared()
            passed = 0 < depth <= 10
            evidence = f"max_loop_depth={depth}"
        elif cid == "tool_permissions_minimal":
            scopes = doc.count_tool_scopes()
            passed = scopes <= 9   # heuristic: <=3 scopes per tool, <=3 tools
            evidence = f"scope declarations found: {scopes}"
        elif cid == "eval_harness_defined":
            passed = doc.has_eval_baseline()
            evidence = "eval baseline keyword found" if passed else "no eval baseline found"
        elif cid == "pii_data_flows_documented":
            passed = doc.pii_documented()
            evidence = "PII reference found" if passed else "no PII documentation found"
        else:
            # Unknown criterion — conservatively fail
            passed = False
            evidence = f"no handler for criterion '{cid}'"

        return CriterionResult(criterion_id=cid, description=desc, passed=passed, evidence=evidence)


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------

def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description="Evaluate design review gate criteria.")
    parser.add_argument("--gate", required=True, help="Gate name (matches YAML filename prefix)")
    parser.add_argument("--design", required=True, help="Path to design document (Markdown)")
    parser.add_argument("--config", required=True, help="Path to gate YAML config")
    parser.add_argument("--output", choices=["text", "json"], default="text")
    args = parser.parse_args(argv)

    design_path = Path(args.design)
    config_path = Path(args.config)

    if not design_path.exists():
        print(f"ERROR: design document not found: {design_path}", file=sys.stderr)
        return 2
    if not config_path.exists():
        print(f"ERROR: gate config not found: {config_path}", file=sys.stderr)
        return 2

    doc = DesignDocParser(design_path)
    evaluator = GateEvaluator(config_path)
    report = evaluator.evaluate(doc)

    if args.output == "json":
        print(json.dumps(report.summary, indent=2))
    else:
        print(f"\n=== Gate: {report.gate_id} ===")
        print("\nAuto criteria:")
        for r in report.auto_results:
            status = "PASS" if r.passed else "FAIL"
            print(f"  [{status}] {r.criterion_id}: {r.evidence}")
        print("\nManual checklist (requires DRB sign-off):")
        for r in report.manual_checklist:
            print(f"  [ ] {r.criterion_id}: {r.description}")
        overall = "PASS" if report.auto_passed else "FAIL"
        print(f"\nOverall auto result: {overall}")

    return 0 if report.auto_passed else 1


if __name__ == "__main__":
    sys.exit(main())
